const input = $input.first().json;
const opps = input.body?.opportunities || input.opportunities || [];
if (!opps.length) return [{ json: { _hasData: false, count: 0 } }];
return opps.map(o => {
  const agency = o.federal_agency?.name || o.agency || '';
  const deptMatch = agency.match(/^Department of (the )?(.*?)(?:\s|$)/i);
  const dept = deptMatch ? deptMatch[2] : agency.split(' ').slice(0, 3).join(' ');
  const desc = (o.descriptions && o.descriptions[0]?.udiff) || '';
  return { json: { solicitation_number: o.solicitation_number || '', opp_title: (o.name || '').replace(/'/g, "''"), agency: agency.replace(/'/g, "''"), dept: dept.replace(/'/g, "''"), naics_code: o.naics_category?.govtribe_id || o.naics_code || '', set_aside: o.set_aside_type || '', govtribe_id: o.govtribe_id || '', source_url: o.govtribe_url || '', response_deadline: o.due_date || null, estimated_value: o.estimated_value || 0, place_of_performance: o.place_of_performance?.name || '', data_source: 'GovTribe', description: desc.substring(0, 500), posted_date: o.posted_date || null, opportunity_type: o.opportunity_type || '', _hasData: true } };
});

const items = $input.all();
const EIS_NAICS = ['541330','541511','541512','541513','541519','541611','541690','541715','541990','611430','561210','561110'];
const TARGET_AGENCIES = ['socom','tradoc','peo stri','inscom','cybercom','disa','indopacom','mda','missile defense','faa'];
function calculateGDAScore(opp) { let score = 0; const title = ((opp.opp_title || '') + ' ' + (opp.description || '')).toLowerCase(); const naics = opp.naics_code || ''; const setAside = (opp.set_aside || '').toLowerCase(); const agency = (opp.agency || '').toLowerCase(); const value = parseFloat(opp.estimated_value || 0); const daysLeft = opp.response_deadline ? Math.ceil((new Date(opp.response_deadline) - new Date()) / 86400000) : 90; score += EIS_NAICS.includes(naics) ? 15 : naics?.startsWith('5415') ? 8 : naics?.startsWith('541') ? 5 : 0; let mp = 0; if (/seta|systems engineering/.test(title)) mp = 15; if (/simulat|training|virtual/.test(title)) mp = Math.max(mp, 12); if (/missile|defense|shield/.test(title)) mp = Math.max(mp, 12); if (/cyber|c5isr/.test(title)) mp = Math.max(mp, 10); if (/intel|intelligence/.test(title)) mp = Math.max(mp, 10); if (/air traffic|atc|faa/.test(title)) mp = Math.max(mp, 8); if (/it support|cloud|network/.test(title)) mp = Math.max(mp, 8); score += Math.min(mp, 15); score += /seta|training|simulat|tradoc/.test(title) ? 10 : /cyber|protect|security/.test(title) ? 10 : /software|engineer|develop/.test(title) ? 10 : /socom|inscom|army/.test(title) ? 7 : 5; score += /sdvosb|service.disabled/.test(setAside) ? 10 : /8\(a\)|8a|competitive 8/.test(setAside) ? 10 : /hubzone/.test(setAside) ? 9 : /small business/.test(setAside) ? 8 : 3; let ppPts = 2; for (const ta of TARGET_AGENCIES) { if (agency.includes(ta)) { ppPts = 15; break; } } if (ppPts < 15 && /army|war/.test(agency)) ppPts = 10; if (ppPts < 10 && /navy|air force|defense/.test(agency)) ppPts = 7; score += ppPts; score += /sole.source|limited/.test(setAside + ' ' + title) ? 10 : /small business/.test(setAside) ? 7 : 3; score += value >= 500000 && value <= 10000000 ? 10 : value > 10000000 ? 8 : value > 100000 ? 4 : 3; score += /iews|recompete/.test(title) ? 10 : /shield|mda/.test(title + ' ' + agency) ? 8 : /idiq|task order/.test(title) ? 6 : 2; score += daysLeft > 45 ? 5 : daysLeft > 30 ? 4 : daysLeft > 14 ? 2 : 1; return Math.min(Math.max(Math.round(score), 0), 100); }
return items.map(item => { const o = item.json; const gda_score = calculateGDAScore(o); return { json: { ...o, gda_score, gda_label: gda_score >= 80 ? 'PURSUE' : gda_score >= 60 ? 'EVALUATE' : gda_score >= 40 ? 'MONITOR' : 'PASS', eis_fit_score: gda_score, stage: 'Identified' } }; });
